@page "/dispatcher"
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize(Roles = "Dispatcher")]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>Dispatcher Dashboard</h1>

<div class="mb-3 d-flex gap-3 align-items-end">
    <div>
        <label class="form-label">Filter by Status</label>
        <select class="form-select" @bind="statusFilter">
            <option value="">All</option>
            @foreach (var s in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@s">@s</option>
            }
        </select>
    </div>
    <button class="btn btn-primary" @onclick="ToggleNewShipmentForm">
        @(showNewForm ? "Cancel" : "New Shipment")
    </button>
</div>

@if (showNewForm)
{
    <div class="card mb-4 p-3">
        <h4>Create New Shipment</h4>
        <div class="row g-2">
            <div class="col-md-4">
                <label class="form-label">Tracking Number</label>
                <input class="form-control" @bind="newShipment.TrackingNumber" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Origin</label>
                <input class="form-control" @bind="newShipment.Origin" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Destination</label>
                <input class="form-control" @bind="newShipment.Destination" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Customer Email</label>
                <input class="form-control" @bind="newShipment.CustomerEmail" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Estimated Delivery</label>
                <input type="date" class="form-control" @bind="newShipment.EstimatedDelivery" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Description</label>
                <input class="form-control" @bind="newShipment.Description" />
            </div>
        </div>
        <button class="btn btn-success mt-3" @onclick="CreateShipment">Create</button>
    </div>
}

@if (shipments is null)
{
    <p>Loading...</p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Created</th>
                <th>Est. Delivery</th>
                <th>Update Status</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
            {
                <tr>
                    <td>@shipment.TrackingNumber</td>
                    <td>@shipment.Destination</td>
                    <td><span class="badge bg-@GetStatusColor(shipment.Status)">@shipment.Status</span></td>
                    <td>@shipment.CreatedDate.ToString("yyyy-MM-dd")</td>
                    <td>@shipment.EstimatedDelivery?.ToString("yyyy-MM-dd")</td>
                    <td>
                        <select class="form-select form-select-sm" value="@shipment.Status"
                                @onchange="e => UpdateStatus(shipment.Id, e)">
                            @foreach (var s in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@s">@s</option>
                            }
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<Shipment>? shipments;
    private string statusFilter = "";
    private bool showNewForm;
    private Shipment newShipment = new();

    private IEnumerable<Shipment> FilteredShipments =>
        string.IsNullOrEmpty(statusFilter)
            ? shipments!
            : shipments!.Where(s => s.Status.ToString() == statusFilter);

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private void ToggleNewShipmentForm() => showNewForm = !showNewForm;

    private async Task CreateShipment()
    {
        await ShipmentService.CreateShipmentAsync(newShipment);
        newShipment = new();
        showNewForm = false;
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private async Task UpdateStatus(int id, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var status))
        {
            await ShipmentService.UpdateShipmentStatusAsync(id, status);
            shipments = await ShipmentService.GetAllShipmentsAsync();
        }
    }

    private static string GetStatusColor(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "secondary",
        ShipmentStatus.PickedUp => "info",
        ShipmentStatus.InTransit => "primary",
        ShipmentStatus.OutForDelivery => "warning",
        ShipmentStatus.Delivered => "success",
        ShipmentStatus.Exception => "danger",
        _ => "secondary"
    };
}

@page "/track"
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="mb-4">
    <div class="input-group" style="max-width: 500px;">
        <input class="form-control" placeholder="Enter tracking number" @bind="trackingNumber" 
               @onkeydown="HandleKeyDown" />
        <button class="btn btn-primary" @onclick="Search">Search</button>
    </div>
</div>

@if (searched && shipment is null)
{
    <div class="alert alert-warning">No shipment found with tracking number "@trackingNumber".</div>
}

@if (shipment is not null)
{
    <div class="card">
        <div class="card-body">
            <h4 class="card-title">Shipment @shipment.TrackingNumber</h4>
            <p class="text-muted">@shipment.Description</p>

            <!-- Progress indicator -->
            <div class="mb-4">
                <div class="d-flex justify-content-between mb-1">
                    @foreach (var step in progressSteps)
                    {
                        <span class="text-center small @(IsStepActive(step) ? "fw-bold text-primary" : "text-muted")">
                            @step
                        </span>
                    }
                </div>
                <div class="progress" style="height: 8px;">
                    <div class="progress-bar" role="progressbar" style="width: @GetProgressPercent()%"></div>
                </div>
            </div>

            <div class="row">
                <div class="col-md-6">
                    <p><strong>Status:</strong> <span class="badge bg-primary">@shipment.Status</span></p>
                    <p><strong>Origin:</strong> @shipment.Origin</p>
                    <p><strong>Destination:</strong> @shipment.Destination</p>
                </div>
                <div class="col-md-6">
                    <p><strong>Created:</strong> @shipment.CreatedDate.ToString("yyyy-MM-dd")</p>
                    <p><strong>Estimated Delivery:</strong> @(shipment.EstimatedDelivery?.ToString("yyyy-MM-dd") ?? "N/A")</p>
                    <p><strong>Customer:</strong> @shipment.CustomerEmail</p>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = "";
    private Shipment? shipment;
    private bool searched;

    private readonly string[] progressSteps = { "Pending", "Picked Up", "In Transit", "Out for Delivery", "Delivered" };

    private async Task Search()
    {
        if (!string.IsNullOrWhiteSpace(trackingNumber))
        {
            shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(trackingNumber.Trim());
            searched = true;
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await Search();
    }

    private bool IsStepActive(string step)
    {
        var stepIndex = Array.IndexOf(progressSteps, step);
        var currentIndex = shipment?.Status switch
        {
            ShipmentStatus.Pending => 0,
            ShipmentStatus.PickedUp => 1,
            ShipmentStatus.InTransit => 2,
            ShipmentStatus.OutForDelivery => 3,
            ShipmentStatus.Delivered => 4,
            _ => -1
        };
        return stepIndex <= currentIndex;
    }

    private int GetProgressPercent() => shipment?.Status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Exception => 50,
        _ => 0
    };
}

